// App.js
// Main React component for CFG Derivation Generator

import React, { useState } from 'react';
import ParseTree from './ParseTree';

// -----------------------------------------------
// Inline styles (no CSS file needed)
// -----------------------------------------------
const s = {
  page: {
    maxWidth: '900px',
    margin: '0 auto',
    padding: '24px 16px',
    fontFamily: 'Arial, sans-serif',
    color: '#222',
  },
  header: {
    textAlign: 'center',
    borderBottom: '2px solid #333',
    paddingBottom: '16px',
    marginBottom: '24px',
  },
  h1: {
    fontSize: '24px',
    marginBottom: '4px',
  },
  subtitle: {
    fontSize: '14px',
    color: '#666',
  },
  section: {
    background: '#f9f9f9',
    border: '1px solid #ddd',
    borderRadius: '8px',
    padding: '16px',
    marginBottom: '20px',
  },
  label: {
    display: 'block',
    fontWeight: 'bold',
    marginBottom: '6px',
    fontSize: '14px',
  },
  textarea: {
    width: '100%',
    height: '120px',
    fontFamily: 'monospace',
    fontSize: '14px',
    padding: '8px',
    border: '1px solid #ccc',
    borderRadius: '4px',
    resize: 'vertical',
    boxSizing: 'border-box',
  },
  input: {
    padding: '8px 12px',
    fontSize: '14px',
    border: '1px solid #ccc',
    borderRadius: '4px',
    fontFamily: 'monospace',
    width: '200px',
  },
  row: {
    display: 'flex',
    gap: '16px',
    alignItems: 'flex-end',
    flexWrap: 'wrap',
  },
  button: {
    padding: '10px 24px',
    fontSize: '15px',
    backgroundColor: '#2563eb',
    color: '#fff',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
    fontWeight: 'bold',
  },
  buttonDisabled: {
    backgroundColor: '#93c5fd',
    cursor: 'not-allowed',
  },
  resultSection: {
    border: '1px solid #ddd',
    borderRadius: '8px',
    marginBottom: '16px',
    overflow: 'hidden',
  },
  resultHeader: {
    background: '#1e3a8a',
    color: '#fff',
    padding: '10px 16px',
    fontSize: '15px',
    fontWeight: 'bold',
  },
  resultBody: {
    padding: '16px',
    background: '#fff',
  },
  stepList: {
    listStyle: 'none',
    padding: 0,
    margin: 0,
  },
  stepItem: {
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    padding: '6px 0',
    borderBottom: '1px solid #f0f0f0',
    fontFamily: 'monospace',
    fontSize: '15px',
  },
  stepNum: {
    background: '#dbeafe',
    color: '#1e3a8a',
    borderRadius: '50%',
    width: '24px',
    height: '24px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '12px',
    fontWeight: 'bold',
    flexShrink: 0,
  },
  arrow: {
    color: '#666',
    fontSize: '14px',
  },
  error: {
    background: '#fee2e2',
    border: '1px solid #ef4444',
    color: '#991b1b',
    padding: '12px 16px',
    borderRadius: '6px',
    marginBottom: '16px',
  },
  hint: {
    fontSize: '12px',
    color: '#666',
    marginTop: '4px',
  },
  loading: {
    textAlign: 'center',
    padding: '20px',
    color: '#666',
  },
  exampleBtn: {
    padding: '4px 10px',
    fontSize: '12px',
    background: '#f0f0f0',
    border: '1px solid #ccc',
    borderRadius: '4px',
    cursor: 'pointer',
    marginRight: '6px',
  },
  successBadge: {
    display: 'inline-block',
    background: '#dcfce7',
    color: '#14532d',
    border: '1px solid #16a34a',
    borderRadius: '12px',
    padding: '2px 10px',
    fontSize: '12px',
    marginLeft: '8px',
  },
  failBadge: {
    display: 'inline-block',
    background: '#fee2e2',
    color: '#991b1b',
    border: '1px solid #ef4444',
    borderRadius: '12px',
    padding: '2px 10px',
    fontSize: '12px',
    marginLeft: '8px',
  },
};

