const EXAMPLES = [
  {
    name: 'aⁿbⁿ',
    grammar: 'S -> aSb | ab',
    input: 'aaabbb',
    start: 'S',
  },
  {
    name: 'Simple AB',
    grammar: 'S -> AB\nA -> aA | a\nB -> bB | b',
    input: 'aab',
    start: 'S',
  },
  {
    name: 'Arithmetic',
    grammar: 'E -> E+T | T\nT -> T*F | F\nF -> id',
    input: 'id+id*id',
    start: 'E',
  },
  {
    name: 'Palindrome',
    grammar: 'S -> aSa | bSb | a | b',
    input: 'aba',
    start: 'S',
  },
];

// -----------------------------------------------
// Derivation Steps Display
// -----------------------------------------------
function DerivationSteps({ result, title }) {
  const isSuccess = result && result.success;

  return (
    <div style={s.resultSection}>
      <div style={s.resultHeader}>
        {title}
        {isSuccess
          ? <span style={s.successBadge}>✓ Found ({result.steps.length} steps)</span>
          : <span style={s.failBadge}>✗ Cannot derive</span>
        }
      </div>
      <div style={s.resultBody}>
        {isSuccess ? (
          <ol style={s.stepList}>
            {result.steps.map((step, i) => (
              <li key={i} style={s.stepItem}>
                <span style={s.stepNum}>{i}</span>
                {i > 0 && <span style={s.arrow}>⇒</span>}
                <span>{step}</span>
              </li>
            ))}
          </ol>
        ) : (
          <p style={{ color: '#ef4444', margin: 0 }}>
            {result ? result.message : 'No result'}
          </p>
        )}
      </div>
    </div>
  );
}

// -----------------------------------------------
// Grammar Rules Display
// -----------------------------------------------
function GrammarDisplay({ rules }) {
  if (!rules || Object.keys(rules).length === 0) return null;

  return (
    <div style={{ ...s.resultSection, marginBottom: '16px' }}>
      <div style={{ ...s.resultHeader, background: '#374151' }}>Parsed Grammar Rules</div>
      <div style={{ ...s.resultBody, fontFamily: 'monospace', fontSize: '14px' }}>
        {Object.entries(rules).map(([lhs, prods]) => (
          <div key={lhs} style={{ marginBottom: '4px' }}>
            <strong>{lhs}</strong> → {prods.map(p => p.join('')).join(' | ')}
          </div>
        ))}
      </div>
    </div>
  );
}

// -----------------------------------------------
// Main App Component
// -----------------------------------------------
function App() {
  const [grammar, setGrammar] = useState('S -> AB\nA -> aA | a\nB -> bB | b');
  const [inputString, setInputString] = useState('aab');
  const [startSymbol, setStartSymbol] = useState('S');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [result, setResult] = useState(null);

  // Load an example
  function loadExample(ex) {
    setGrammar(ex.grammar);
    setInputString(ex.input);
    setStartSymbol(ex.start);
    setResult(null);
    setError('');
  }

  // Submit to backend
  async function handleGenerate() {
    setError('');
    setResult(null);

    // Basic client-side validation
    if (!grammar.trim()) {
      setError('Please enter grammar rules.');
      return;
    }
    if (inputString === undefined || inputString === null) {
      setError('Please enter an input string (can be empty for epsilon).');
      return;
    }
    if (!startSymbol.trim()) {
      setError('Please enter a start symbol.');
      return;
    }

    setLoading(true);

    try {
      const response = await fetch('/api/derive', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          grammar: grammar,
          input: inputString,
          startSymbol: startSymbol.trim(),
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        setError(data.error || 'Server error. Check backend is running.');
        return;
      }

      setResult(data);
    } catch (err) {
      setError('Cannot connect to backend. Make sure the server is running on port 5000.\n\nRun: cd backend && npm start');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={s.page}>
      {/* Header */}
      <div style={s.header}>
        <h1 style={s.h1}>CFG Derivation & Parse Tree Generator</h1>
        <p style={s.subtitle}>Context-Free Grammar · Leftmost & Rightmost Derivation · Parse Tree</p>
      </div>

      {/* Examples */}
      <div style={{ marginBottom: '16px' }}>
        <span style={{ fontSize: '13px', color: '#555', marginRight: '8px' }}>Quick examples:</span>
        {EXAMPLES.map((ex) => (
          <button key={ex.name} style={s.exampleBtn} onClick={() => loadExample(ex)}>
            {ex.name}
          </button>
        ))}
      </div>

      {/* Input Section */}
      <div style={s.section}>
        {/* Grammar Input */}
        <div style={{ marginBottom: '16px' }}>
          <label style={s.label}>Grammar Rules</label>
          <textarea
            style={s.textarea}
            value={grammar}
            onChange={(e) => setGrammar(e.target.value)}
            placeholder={"S -> AB\nA -> aA | a\nB -> bB | b"}
          />
          <p style={s.hint}>
            Format: <code>LHS -&gt; symbols | alternatives</code>. One rule per line.
            Uppercase = non-terminals, lowercase = terminals.
          </p>
        </div>

        {/* String + Start Symbol */}
        <div style={s.row}>
          <div>
            <label style={s.label}>Start Symbol</label>
            <input
              style={{ ...s.input, width: '80px' }}
              value={startSymbol}
              onChange={(e) => setStartSymbol(e.target.value)}
              maxLength={5}
            />
          </div>
          <div>
            <label style={s.label}>Input String</label>
            <input
              style={s.input}
              value={inputString}
              onChange={(e) => setInputString(e.target.value)}
              placeholder="e.g. aabb"
            />
          </div>
          <button
            style={{ ...s.button, ...(loading ? s.buttonDisabled : {}) }}
            onClick={handleGenerate}
            disabled={loading}
          >
            {loading ? 'Generating...' : '▶ Generate'}
          </button>
        </div>
      </div>

      {/* Error */}
      {error && (
        <div style={s.error}>
          <strong>Error:</strong> {error}
        </div>
      )}

      {/* Loading */}
      {loading && <div style={s.loading}>⏳ Computing derivations...</div>}

      {/* Results */}
      {result && (
        <div>
          {/* Parsed Grammar */}
          <GrammarDisplay rules={result.grammarRules} />

          {/* Leftmost Derivation */}
          <DerivationSteps
            result={result.leftmost}
            title="Leftmost Derivation (LMD)"
          />

          {/* Rightmost Derivation */}
          <DerivationSteps
            result={result.rightmost}
            title="Rightmost Derivation (RMD)"
          />

          {/* Parse Tree */}
          <div style={s.resultSection}>
            <div style={{ ...s.resultHeader, background: '#065f46' }}>
              Parse Tree
              {result.parseTree
                ? <span style={s.successBadge}>✓ Generated</span>
                : <span style={s.failBadge}>✗ Not available</span>
              }
            </div>
            <div style={s.resultBody}>
              <ParseTree tree={result.parseTree} />
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <div style={{ textAlign: 'center', color: '#999', fontSize: '12px', marginTop: '32px' }}>
        CFG Derivation Generator · College Assignment Project
      </div>
    </div>
  );
}

export default App;
